  ('MATH-G3-DH-SCO51', 'MATH-G3-DH-ELO8', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Willingly participate in activities', 1619, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO52', 'MATH-G3-DH-ELO8', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Ask questions to understand concepts relating to probability.', 1620, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO53', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Differentiate between the terms ‘impossible’ and ‘certain’ in relation to real- life events.', 1621, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO54', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Calculate the possibility of an event happening.', 1622, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO55', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Define probability and its relationship to relative frequency of an item or event.', 1623, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO56', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Classify events as being impossible or certain.', 1624, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO57', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Calculate probabilities by counting the outcomes in a graph.', 1625, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO58', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Solve simple problems involving probability.', 1626, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO59', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Willingly participate in activities in and outside the classroom that involve determining the probability of given life events occurring.', 1627, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-DH-SCO60', 'MATH-G3-DH-ELO9', 'MATH-G3-DH', 'MATH', 'mathematics', 'G3', '3', 'Data Handling ', 'Appreciate the use of probability as a measure of chance.', 1628, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO1', 'MATH-G3-PR-ELO1', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify the relationship between repeated addition when multiplying.', 1629, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO2', 'MATH-G3-PR-ELO1', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Describe the pattern in the product of numbers multiplied by 2-12', 1630, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO3', 'MATH-G3-PR-ELO1', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Discover patterns in multiplication fact families.', 1631, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO4', 'MATH-G3-PR-ELO1', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Justify your solution of the missing number in an addition or multiplication pattern.', 1632, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO5', 'MATH-G3-PR-ELO1', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Volunteer to solve authentic problems by discovering the patterns.', 1633, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO6', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify and copy repeating elements in a repeating pattern.', 1634, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO7', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Explain the rule used to create a repeating nonnumerical pattern.', 1635, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO8', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify the rule in an increasing and decreasing pattern.', 1636, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO9', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify errors in an increasing and decreasing pattern.', 1637, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO10', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Translate a pattern to a different medium (e.g., clap, jump, clap, jump instead of triangle, circle, triangle, circle).', 1638, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO11', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Represent an increasing and decreasing pattern concretely and pictorially and explain the rule.', 1639, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO12', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Extend the element in an increasing and decreasing pattern.', 1640, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO13', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify and describe increasing and decreasing patterns in various contexts(e.g., a hundred chart, number line, addition tables, a calendar, a tiling pattern, or drawings).', 1641, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO14', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Solve a problem using increasing and decreasing patterns.', 1642, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO15', 'MATH-G3-PR-ELO2', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Create problems with repeating and increasing environmental patterns (e.g., house/room numbers, flower petals, book pages, calendar, pinecones, leap years).', 1643, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO16', 'MATH-G3-PR-ELO3', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify the inverse function of operations. (Example: 4 + 5 = 9, 9-5=4)', 1644, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO17', 'MATH-G3-PR-ELO3', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Represent an unknown quantity with a letter or symbol can be used to represent ', 1645, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO18', 'MATH-G3-PR-ELO3', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Use the part-part-whole model to demonstrate the inverse function of operations.', 1646, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO19', 'MATH-G3-PR-ELO3', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Use the part-part-whole model to solve open sentences in addition/ subtraction and multiplication and division fact families.', 1647, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO20', 'MATH-G3-PR-ELO3', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Demonstrate a positive attitude when solving problems with one unknown.', 1648, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G3-PR-SCO21', 'MATH-G3-PR-ELO4', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'State the definition of the following vocabulary words:” equal, unequal, quantity, and compare.', 1649, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO22', 'MATH-G3-PR-ELO4', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Use equal and unequal symbols correctly when comparing.', 1650, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO23', 'MATH-G3-PR-ELO4', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Demonstrate how to compare two quantities using symbols such as = for equal and ≠ not equal, > for greater than and < for lesser than.', 1651, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO24', 'MATH-G3-PR-ELO4', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Recognize the importance of equality in solving problems.', 1652, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO25', 'MATH-G3-PR-ELO5', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify variables (represented as letters or symbols) within mathematical expressions or equations.', 1653, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO26', 'MATH-G3-PR-ELO5', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Write simple mathematical expressions using variables to represent unknown quantities (e.g., 3 + x = 7).', 1654, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO27', 'MATH-G3-PR-ELO5', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Write basic equations using variables, demonstrating the concept of equality(e.g., x + 5 = 12).', 1655, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO28', 'MATH-G3-PR-ELO5', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Recognize relationships between numbers and variables in simple mathematical contexts.', 1656, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO29', 'MATH-G3-PR-ELO5', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Solve basic addition and subtraction equations to find the variable''s value (e.g., x - 3 = 8, x = 11). Create word problems involving variables, requiring classmates ', 1657, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO30', 'MATH-G3-PR-ELO6', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify the relationship/pattern by using different representations (tables graphs, and simple equations)', 1658, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO31', 'MATH-G3-PR-ELO6', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Recognize and describe patterns in number sequences and tables ', 1659, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO32', 'MATH-G3-PR-ELO6', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify the relationship between input and output values. ', 1660, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO33', 'MATH-G3-PR-ELO6', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Determine the function between the input and output ', 1661, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO34', 'MATH-G3-PR-ELO6', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Explain how the input and output values are related in simple functions, using appropriate language ', 1662, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO35', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Identify relationships to make accurate predictions about future data points or outcomes,', 1663, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO36', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Use patterns and trends to identify relationships', 1664, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO37', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Make predictions based on identified relationships', 1665, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO38', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'using appropriate language and supporting assertions with evidence from patterns.', 1666, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO39', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Explain reasoning when making predictions or generalizations in patterns,', 1667, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO40', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Justify the relationships identified.', 1668, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO41', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Collaborate in analysing data sets and identifying relationships,', 1669, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO42', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Discuss patterns and predictions as a group and share insights and interpretations.', 1670, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO43', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Create tables, listing input and output pairs for simple functions (e.g., 2 times the input number).', 1671, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO44', 'MATH-G3-PR-ELO7', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Students will represent relationships such as addition or subtraction pattern.', 1672, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO45', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Describe simple mathematical functions, such as addition, subtraction, multiplication, and division.', 1673, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO46', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Write open sentences (equations or expressions with blanks) to represent mathematical relationships in real-world situations.', 1674, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO47', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Solve open sentences to find the missing values or variables using appropriate operations and strategies.', 1675, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO48', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Translate verbal descriptions of real-life scenarios into open sentences, focusing on identifying key information and variables.', 1676, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO49', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Create story or word problems involving simple functions and relationships represented by open sentences.', 1677, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO50', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Apply addition and subtraction operations to situations involving combining or taking away quantities, such as money, objects, or time.', 1678, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO51', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Apply multiplication and division operations to situations involving equal groups, sharing, or repeated addition.', 1679, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G3-PR-SCO52', 'MATH-G3-PR-ELO8', 'MATH-G3-PR', 'MATH', 'mathematics', 'G3', '3', 'Patterns and Relationships', 'Check and validate solutions to story problems by using inverse operations or estimating to see if the answer makes sense in the context of the problem.', 1680, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO1', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Engage with and share various genres of music, oral poetry, artwork, and oral stories that have been chosen for pleasure.', 1681, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO2', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Experience and enjoy playful use of language, to communicate e.g., telling jokes, asking riddles, singing songs, composing rhymes and verses.', 1682, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO3', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Respond to oral/aural language through improvisational drama and/or artwork.', 1683, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO4', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Listen attentively and critically to fiction and nonfiction text and music to demonstrate understanding of:
•	the mood
•	main idea
•	some supporting details', 1684, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO5', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Continue to develop strategies to describe, share, and discuss thoughts, feelings, and experiences with peers.', 1685, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO6', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Ask and respond to questions to clarify information and to explore possibilities or solutions to problems.', 1686, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO7', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Listen critically for subtle messages in conversation, music, and environmental sounds.', 1687, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO8', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Create and use oral instructions describing how to make or do something.', 1688, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO9', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Discuss solutions to local, regional and world events by extending use of questioning to consider: why? how? when?  what if?  what else?, etc.', 1689, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO10', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Demonstrate understanding and use of conversation courtesies during peer group work, class discussions and play.', 1690, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO11', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Use vocabulary that shows respect for all people.', 1691, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO12', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Listen attentively and build on others’ ideas with increasing confidence in group and class discussions and individual presentations.', 1692, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO13', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Continue to develop understanding of point of view without expressing judgment.', 1693, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO14', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Explore ideas and feelings by asking respectful questions and listening with minimal interruption.', 1694, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO15', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Use and respond to verbal and nonverbal cues respectfully.', 1695, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO16', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Develop confidence in asking for assistance from peers and adults.', 1696, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO17', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Retell stories and events with peers and engage in follow up conversations.', 1697, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO18', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Share relevant ideas, opinions, and feelings on topics of personal and social interest using both Standard English and Home Languages.', 1698, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G3-LS-SCO19', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Develop an appreciation for various forms of language and their appropriateness to different situations.', 1699, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO20', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Use thoughtful, respectful, and non-hurtful vocabulary.', 1700, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO21', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Continue to develop oral comprehension strategies to determine word meanings.', 1701, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO22', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Participate in the sharing of culturally relevant songs, raps, drama, and poetry with fluency, rhythm, and pace.', 1702, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO23', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Continue to develop understanding of how and when to adjust volume, projection, facial expressions, gestures, and tone of voice to the speaking occasion.', 1703, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-LS-SCO24', 'LANG-G3-LS-ELO1', 'LANG-G3-LS', 'LANG', 'language-arts', 'G3', '3', 'Listening and Speaking', 'Continue to develop meaningful language use and conventions of oral language(s) as appropriate to the context and purpose:
•	word order
•	increasingly varied vocabulary choices for nouns, verbs, adjectives, adverbs
•	use of descriptive language (similes, beginning use of metaphors)
•	use of affixes
•	subject and verb agreement correctly in delivering spoken messages and in planned oral presentations.', 1704, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO1', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to choose and engage with a range of literary, visual, graphic, and informational texts for independent reading.', 1705, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO2', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of the of fiction, poetry, and nonfiction genres to guide independent understanding of visual and text-based information. ', 1706, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO3', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Known comprehension strategies during independent reading: 
•	determining the main idea
•	making connections
•	predicting
•	visualising
•	inferring
•	analysing
•	synthesising', 1707, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO4', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Demonstrate understanding of texts read independently through a variety of oral, written, visual responses such as:
•	artistic representations (visual arts, song, dance)
•	discussions
•	graphic organizers
•	oral and written responses to questions', 1708, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO5', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to respond critically to texts by asking and formulating responses to questions such as:  
•	what if?
•	is it possible that . . .?
•	what else?
•	what was the author trying to tell us?
•	do I agree / why?', 1709, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO6', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Describe how the sequence of events and setting of fiction and nonfiction genres impacts the plot or the event described.', 1710, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO7', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of characterization by:
•	describing the character’s attributes (traits, motivations or feelings);
•	using evidence from the text to support generalizations about the character;
•	comparing and contrasting characters within a selection or between/among two or more selections;
•	explaining how the actions of characters contribute to the sequence of events describing the impact of a character’s response to a problem, the character’s goal, and what the character says or thinks.', 1711, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO8', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to make connections between the vocabulary of Home Language(s) and Standard English.', 1712, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO9', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Become increasingly aware of how local texts use the history and roots of the local language(s). ', 1713, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO10', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to develop reading vocabulary through reading a range of genres, authors, and topics.', 1714, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO11', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Extend reading vocabulary with increasing independence through the application of
•	antonyms
•	synonyms
•	homophones
•	homographs', 1715, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO12', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Use a paper-based or digital dictionary and thesaurus with increasing independence.', 1716, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO13', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to independently apply common prefixes and suffixes to determine meaning of new vocabulary.', 1717, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO14', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply cross-curricular vocabulary to enhance understanding of texts read during independent reading. ', 1718, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO15', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of the change in tense (-ed), number (-s), and degree (-er and –est) signified by inflected endings to decode words.', 1719, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO16', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Identify and apply figurative language to enhance understanding of a text.', 1720, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO17', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to demonstrate understanding of how word order impacts meaning. ', 1721, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO18', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of how personal reading fluency impacts understanding.', 1722, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO19', 'LANG-G3-RV-ELO1', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Develop an awareness of how word choice, phrasing and punctuation may be used in positive or negative ways.', 1723, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO20', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to apply knowledge of the organizational structure of fiction, nonfiction, and poetry genres to guide understanding of visual and text-based information. ', 1724, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO21', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to apply and combine comprehension strategies listed below to demonstrate understanding of literary, visual, graphic, and informational texts:
•	determining main idea
•	making connections
•	predicting
•	visualising
•	inferring
•	analysing
•	synthesising', 1725, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO22', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Demonstrate understanding through a variety of oral, written visual responses such as:
•	artistic representations (visual arts, song, dance)
•	discussions
•	graphic organizers
•	oral and written responses to questions', 1726, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO23', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to respond critically to texts by asking and formulating responses to questions such as: 
•	what if?
•	is it possible that . . .?
•	what else?
•	what was the author trying to tell us? 
•	do I agree / why?', 1727, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO24', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Choose and apply a range of human, paper based and digital sources of information e.g., community experts, online searches, web, and text-based reference materials, etc. ', 1728, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO25', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Describe how the sequence of events and setting of fiction and nonfiction genres impacts the plot or the event described.', 1729, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO26', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of characterization by:
•	describing the character’s attributes (traits, motivations, or feelings);
•	using evidence from the text to support generalizations about the character;
•	comparing and contrasting characters within a selection or between/among two or more selections;
•	explaining how the actions of characters contribute to the sequence of events
•	describing the impact of a character’s response to a problem, the character’s goal, and what the character says or thinks', 1730, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO27', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to make connections between the texts using vocabulary of Home Language(s) and Standard English to become increasingly aware of the history and roots of  local language(s). ', 1731, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO28', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to develop reading vocabulary using accompanying images in a range of genres, authors, and topics.', 1732, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G4-SF-SCO13', 'SCIENCE-G4-SF-ELO1', 'SCIENCE-G4-SF', 'SCIENCE', 'science', 'G4', '4', 'Structure and Function ', 'Measure temperatures.', 3062, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G3-RV-SCO29', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Extend reading vocabulary through the application of
•	compound words
•	adjectives
•	antonyms
•	synonyms
•	homophones
•	homographs', 1733, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO30', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Use a paper based or online dictionary, thesaurus or online vocabulary games to learn the meaning and other features of known and unknown words.', 1734, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO31', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to apply common prefixes and suffixes to determine meaning of new vocabulary.', 1735, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO32', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Extend vocabulary by applying technical terms encountered during cross-curricular learning.', 1736, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO33', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of the change in tense (-ed), number (-s), and degree (-er and –est) signified by inflected endings to decode words.', 1737, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO34', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Identify and apply figurative language to enhance understanding text.', 1738, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO35', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to demonstrate understanding of how word order impacts meaning. ', 1739, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO36', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of how reading fluency impacts understanding.', 1740, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO37', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Participate in shared reading opportunities (drama, role -play, reading lyrics while singing, etc. to
•	enhance fluency
•	guide intonation
•	convey the mood and intent of the text
•	demonstrate expression', 1741, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO38', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Develop awareness of how word choice and phrasing may be used to describe in positive or negative ways.', 1742, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO39', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Further develop understanding of the purpose and use of:
•	Nouns
•	Verbs
•	Adjectives
•	Adverbs
•	Pronouns', 1743, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO40', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to apply background knowledge and context clues to read irregularly spelled words.', 1744, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO41', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Apply knowledge of roots and affixes to decode unknown words.', 1745, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO42', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to monitor (self check) reading for unknown words and use a combination of cues (meaning, grammar, and graphophonic) to solve unknown reading vocabulary with automaticity.', 1746, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO43', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to apply grade-level phonics and word analysis skills with increasing automaticity:
•	the letter order, various sounds of vowels, vowel patterns (ou/ow, oi/oy, oo, aw), and some consonants (c,g)
•	the sounds of common digraphs and diphthongs
•	complex letter pattern
•	words with silent letters', 1747, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G3-RV-SCO44', 'LANG-G3-RV-ELO2', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Decode new and unfamiliar words using:
•	affixes
•	syllabication
•	inflectional endings', 1748, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO45', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to notice and compare the purpose and style of a variety of authors and illustrators.', 1749, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO46', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Develop understanding of the basic features of the plots of fables, folk tales, fairy tales, adventure stories etc.', 1750, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO47', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Discuss the purpose of particular images or media texts e.g., to inform, entertain, and persuade.', 1751, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO48', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Begin to develop an understanding of the component of author’s style. ', 1752, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO49', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Recognize a variety of text forms, text features and stylistic elements and how they help communicate meaning.', 1753, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO50', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Refer to parts of stories, dramas and poems when writing or speaking about text using terms such as chapter, scene, and stanza, describe how each successive part builds on earlier sections.', 1754, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO51', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Refine use of a variety of text features to locate information (table of contents, glossary, index, charts, titles, and subtitles, etc.).', 1755, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO52', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Generate questions to guide research and:
•	locate appropriate information with assistance (classroom, library, home, community)
•	organise information
•	share information', 1756, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO53', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Use charts, diagrams, and other graphic information in an expository selection as an aid to understanding the text.', 1757, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO54', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Evaluate the contribution of graphic information to an expository selection.', 1758, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO55', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Use information gained from illustrations e.g., maps, photographs, and the words in a text to demonstrate understanding of the text.', 1759, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO56', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to develop understanding of how illustrations, fonts, vocabulary and language structures are designed to engage the reader', 1760, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO57', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to provide examples of author’s use of interesting words, phrases, and sentences to evoke emotions, describe, create humour, etc.', 1761, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO58', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Explain how specific aspects of a text’s illustrations contribute to what is being conveyed by words in the text, e.g., create mood and emphasize setting.', 1762, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO59', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Compare and contrast the effectiveness, cultural relevance and possible hidden messages of advertisements, social media posts, etc. used to influence the reader - provide unwritten information', 1763, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO60', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Continue to search for and compare the purpose and style of a variety of authors and illustrators.', 1764, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-RV-SCO61', 'LANG-G3-RV-ELO3', 'LANG-G3-RV', 'LANG', 'language-arts', 'G3', '3', 'Reading and Viewing', 'Develop understanding of how the author develops the basic features of the plots of fables, folk tales, fairy tales, adventure stories etc.', 1765, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO1', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Maintain a personal record of interests, personal or community experiences, music, books, pictures for use as writing prompts.', 1766, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO2', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Maintain a writing portfolio that includes drafts, revisions, personal dictionary, personal writing prompts, etc.', 1767, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO3', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Identify the topic, purpose, audience, and form for writing.', 1768, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO4', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Participate in group and individual brainstorming to gather ideas for their writing, to write for an intended purpose and audience.', 1769, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO5', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Become familiar with a variety of paper based and digital brainstorming techniques:
•	talk about the ideas they plan to write about
•	draw pictures to develop ideas for writing
•	create jot notes for research writing', 1770, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO6', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Gather information from a variety of paper based and digital resources to support and enhance brainstorm.', 1771, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO7', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Reflect on ideas gathered and add, revise, or delete to suit to topic and genre.', 1772, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO8', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Organize ideas and information to write for an intended purpose and audience using:
•	paper based or digital graphic organizers
•	samples of how published texts are organized', 1773, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO9', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Further develop independence in using, choosing, and creating simple graphic organizers.', 1774, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO10', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Participate and contribute to shared writing opportunities that reflect the genre', 1775, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO11', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'studied (e.g., newsletters to parents, thankyou letters to classroom guests, lists of classroom procedures, recipes, labels).', 1776, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO12', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Write a simple nonfiction report on a topic of personal relevance.', 1777, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO13', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Explore and begin to use blogs, google classroom diary, social media to contribute to various genres of writing. ', 1778, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO14', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Refer to texts and conversations as anchors for organising a sequence of events, changes in setting, and character development.', 1779, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO15', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Further develop understanding of the purpose and organisation of: 
•	narrative writing
•	expository writing
•	opinion writing
•	persuasive writing 
•	report writing  ', 1780, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO16', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Continue to develop and apply understanding of the Writing Traits of Ideas, Organisation and Language Use with increasing independence.', 1781, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO17', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Enhance understanding of how to use transition words and phrases to develop a logical progression of ideas and thoughts (e.g., because, therefore, since, for example) to connect opinion and reasons.', 1782, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO18', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Explore possibilities provided in anchor texts of various ways to convey ideas, through 
•	introductory sentences
•	concluding sentences
•	sequencing of ideas
•	vocabulary choices
•	simple, compound, and complex sentences.', 1783, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO19', 'LANG-G3-WR-ELO1', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Apply, with increasing independence, the understanding and application of Ideas, Organisation and Language Use in draft writing in a range of genres.', 1784, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO20', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Continue to develop self assessment revision strategies by self monitoring writing for form and organisation using paper based or digital revision tools such as: 
•	caret,
•	crossing out
•	adding /removing details
•	arrows to organise', 1785, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO21', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Use feedback given by peers and teachers as an aid in writing and strengthening the organization of the draft', 1786, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO22', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Experiment with digital and paper-based organisation with various real-world genres: (wish list, how to list, grocery list, play lists, etc.)', 1787, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO23', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Continue to appreciate and develop the purpose and place of Home Language and Standard English vocabulary. ', 1788, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO24', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Continue to develop self monitoring of errors in word use.', 1789, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO25', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Explore synonyms to enhance, clarify and expand information. ', 1790, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO26', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Connect the use of sensory verbs, adjectives, and adverbs to enliven language.', 1791, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO27', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Demonstrate understanding of figurative language by using simple similes, metaphors, and personification in their writing.', 1792, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO28', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Use a paper based or digital dictionary or thesaurus to clarify the meaning of keywords.', 1793, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO29', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Recognize and use words with multiple meanings with understanding and intent.', 1794, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO30', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Acknowledge the importance and purpose of the grammar of Home Language(s), standard and informal writing.', 1795, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO31', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Revise with a focus on monitoring for complete and well-formed sentences that are clear and understandable.', 1796, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO32', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Continue to engage in individual and shared peer revision opportunities to share drafts aloud and provide/ receive feedback on elements of grammar and sentence fluency such as:
•	use of simple verb tenses
•	comparative and superlative adjectives and adverbs,
•	form and use possessives.
•	subject and verb agreement
•	meaningful use of simple, compound, and complex sentence patterns meaningfully
•	determining complete and incomplete sentences', 1797, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G3-WR-SCO33', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Begin to use a simple digital grammar checker.', 1798, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO34', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Begin to notice how favourite authors use language and why it is engaging.', 1799, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO35', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Experiment with a variety of writing styles to develop a sense of authorship.', 1800, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO36', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Experiment with writing from another perspective (an animal, an alien, etc.).', 1801, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO37', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Experiment with character, dialogue and descriptions of actions, thoughts, and feelings to fully develop character.', 1802, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO38', 'LANG-G3-WR-ELO2', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Experiment with real or imagined experiences or events using descriptive details and intentional sequences of event.', 1803, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO39', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Continue to develop spelling accuracy and automaticity.', 1804, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO40', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Use temporary (or attempted) spelling with an increasing knowledge of spelling patterns of language(s) in common use.', 1805, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO41', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Continue to refine the use spelling patterns and generalizations such as:
•	phonetic position-based spellings (beginning, middle and ending sounds)
•	rhyming word families
•	syllable patterns
•	meaningful use of affixes and root words
•	knowledge of some irregularly spelled words
•	use frequently confused words (e.g., to/too/two; there/their) with increased accuracy. 
•	regular and some irregular ending rules ', 1806, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO42', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Consult reference materials, including paper based, digital dictionaries and spell check, to monitor and correct spellings.', 1807, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO43', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Use technology to produce and publish writing (using keyboarding skills) as well as to interact and collaborate with others. Apply strategies for editing and presenting during the writing process.', 1808, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO44', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Engage in the editing process by completing a close read of revised draft.', 1809, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO45', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Demonstrate increased understanding of the purpose and meaningful use of capitals and punctuation (and variations of punctuation among English and local languages)
•	capitals for sentence beginnings, names, titles, etc.
•	punctuation as full stops, exclamation marks and question marks
•	punctuation as beginning use of commas and colon to begin a list', 1810, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO46', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Further develop accuracy and neatness in handwritten work.', 1811, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO47', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Create presentations of stories and reports in various paper based or digital formats that are engaging to the reader.', 1812, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('LANG-G3-WR-SCO48', 'LANG-G3-WR-ELO3', 'LANG-G3-WR', 'LANG', 'language-arts', 'G3', '3', 'Writing and Representing', 'Demonstrate beginning use of fonts, graphics, letter size, spacing etc. to express their thoughts and engage the reader.', 1813, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO1', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Define the terms:
•	Pull
•	Push
•	force
•	speed
•	velocity
•	frictional force
•	mass
•	balanced force
•	unbalanced force
•	gravity force
•	magnetic force', 1814, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO2', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Identify forces as pushes or pulls.', 1815, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO3', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Identify forces used to create movement or change in given situations.', 1816, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO4', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Give examples of balanced and unbalanced forces.', 1817, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO5', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Describe the effects of balanced and unbalanced forces acting on a variety of everyday objects.', 1818, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO6', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Identify force as a push or pull by one body on another.', 1819, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO7', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Identify, demonstrate and give examples of push and pulls (ST 1 PS FMS 1).', 1820, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO8', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Describe and demonstrate the forces of push and pull. (ST 3 PS FMS 1).', 1821, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO9', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Identify, with examples, forces at work in everyday situations in the home and community. (ST 3 PS FMS 2).', 1822, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO10', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Describe the visible effects of push and pull on a variety of everyday objects. (ST 4 PS FMS 4).', 1823, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO11', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Compare balanced and unbalanced forces using a Venn Diagram.', 1824, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO48', 'SCIENCE-G3-FI-ELO2', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Work safely when participating in various activities.', 1861, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
