  ('SCIENCE-G3-FI-SCO13', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Demonstrate the effect of balanced forces on objects.', 1826, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO14', 'SCIENCE-G3-FI-ELO1', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Conduct an Investigation on the ways in which different forces (e.g. magnetism, static electricity, muscular force, gravitational force) can change the speed and direction of a moving object.', 1827, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
