  ('SCIENCE-G3-FI-SCO80', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Suggest novel and innovative ways of using a magnet in the home. (ST 4 PS FMS 5)', 1893, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO81', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Design and construct a simple object using chosen materials. (ST 2 PS MM 4)', 1894, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO82', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Given problems, be able to design and construct simple gadgets. (ST 2 TE TM 1)', 1895, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO83', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Appreciation of how magnets make life easier', 1896, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO84', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Realize the critical importance of safety in handling tools and making gadgets. (ST 2 TE NT 3) (Safety)', 1897, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G3-FI-SCO85', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 1898, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO86', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Participate actively in classroom discussions.', 1899, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-FI-SCO87', 'SCIENCE-G3-FI-ELO4', 'SCIENCE-G3-FI', 'SCIENCE', 'science', 'G3', '3', 'Forces and Interactions', 'Share information with peers in a collaborative manner on the nature of technology. (ST 2 TE NT 2)', 1900, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO1', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Define the terms:
•	survive
•	groups (e.g. herds, nests, swarm, packs, pride, troops,
•	flocks, etc.)
•	members
•	social
•	solitary
•	predator and prey relationship
•	structure or organization within a group', 1901, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO2', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify and name the different types of ecosystems in the country indicating their location on a map (ST 3 LS ECS 4).', 1902, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO3', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify collective nouns used to describe common groups of animals such as a pride of lions, a herd of cow, troop of monkeys, a swarm of bees, flock of sheep or birds, etc.', 1903, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO4', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identifying types of animals (e.g. honey bees, jack Spaniard wasps, termites, elephants, wolves, sheep, goats, whales, dolphins, mosquitoes, lizards, monkeys, lions, birds) that form or live in groups of varying sizes.', 1904, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO5', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identifying at least one animal that does not live in a group.', 1905, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO6', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explaining how some animals are able to survive alone.', 1906, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO7', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Showing situations when it is better to live in a group than as an individual.', 1907, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO8', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explaining the roles of different animals in a group.', 1908, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO9', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explaining how the different roles of members in a group benefits the group as a whole.', 1909, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO10', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Giving multiple examples of animals in groups of various sizes:  
1.	Obtaining more food for each individual animal compared to the same type of animal looking for food individually. 
2.	Displaying more success in defending themselves than those same animals acting alone. 
3.	Making faster or better adjustments to harmful changes in their ecosystem than would those same animals acting alone.', 1910, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO11', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Observe the behaviour of individuals in a group.', 1911, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO12', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compare how an individual member of a group of animals behaves when it is in the group and when it is separated from the group.', 1912, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO13', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Infer what could happen to members of a group if they are separated from the group.', 1913, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO14', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Communicate information gained from observations, texts, videos etc. with members of your group and the class.', 1914, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO15', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Predict how members of a named animal group may respond to certain changes in their environment.', 1915, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO16', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compile data on the behaviour of different members of identified/named groups.', 1916, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO17', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Analyse data on the behaviour of different members of identified/named groups.', 1917, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO18', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Graph data provided/generated on the behaviour of different members of identified/named groups', 1918, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO19', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Interpret data provided/generated on the behaviour of different members of identified/named groups', 1919, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO20', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Show an appreciation for the work that scientists do in studying animal behaviour.', 1920, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO21', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Appreciate that there are solitary animals.', 1921, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO22', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Be persistent when studying the various groups as it can take a lot of time.', 1922, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO23', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Show interest in what is happening in the group or at the class level.', 1923, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO24', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Use the inquiry approach in conducting various investigations.', 1924, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO25', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Show respect for evidence in making various claims about animals living in groups', 1925, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO26', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Develop different ways that animals may be studied.', 1926, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO27', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Design ways to model the behaviour of different members of a group.', 1927, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO28', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Work collaboratively with their group members to complete various tasks.', 1928, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO29', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'When observing animals, students should make sure that the animals or the environment are not harmed.', 1929, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO30', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'While observing animals, students should exhibit appropriate behaviour to ensure that the animals or students did not get hurt.', 1930, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO31', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'While observing animals, students should be respectful of the animals they study.', 1931, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO32', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Students should be aware that some animals can harm them. For example, ants can bite.', 1932, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO33', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'When conducting practical and group work, students should display sensitivity and offer assistance to classmates/group members who may have physical or learning challenges.', 1933, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO34', 'SCIENCE-G3-IRE-ELO1', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Participate actively in classroom discussions.', 1934, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO35', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Define the terms:
•	Adaptations
•	Ecosystem
•	Environmental balance
•	Habitat
•	Interdependence
•	Diversity
•	Abiotic
•	Biotic', 1935, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO36', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Demonstrate that they understand that habitats are different and that some animals survive well in a particular habitat, some survive less well, and some cannot survive at all.', 1936, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO37', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Show evidence that in a particular habitat, some organisms can survive well, some survive less well, and some cannot survive at all.', 1937, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO38', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Account for adaptations observed in organisms found in different habitats.', 1938, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO39', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain how some features of organisms enable their survival in their habitats. (ST 2 LS ECS 5)', 1939, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO40', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Distinguish between activities that harm and those that preserve habitat/the environment. (ST 2 LS ECS 6)', 1940, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO41', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain, with examples, what are endangered species. (ST 2 LS ECS 12)', 1941, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO42', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify and describe ways of protecting endangered species e.g. laws, change of human''s attitudes to life and the environment. (ST 2 LS ECS 13)', 1942, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO43', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain how adaptations of organisms enable their survival in their habitats.', 1943, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO44', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain how some features of organisms enable their survival in their habitats. (ST 2 LS ECS 5)', 1944, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO45', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify, with examples, ways in which organisms in a particular habitat depend on each other (feeding, shelter, protection, beauty)', 1945, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO46', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify, with examples, ways in which plants and animals depend on each other (feeding, shelter, protection, beauty) (ST 2 LS ECS 17)', 1946, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO47', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain to their classmates the need for environmental conservation in their country, outlining possible scenarios if such protection is neglected. (ST 3 LS ECS 7)', 1947, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G3-IRE-SCO48', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Reiterate the meaning of the concept of balance in the environment. (ST 3 LS ECS 5)', 1948, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO49', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain that living things compete for food and space in the environment and describe how breaking the flow or supply of food can have serious consequences. (ST 5 LS ECS 2)', 1949, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO50', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain with examples, the ways in which the structure of the land influences the types of ecosystems. (ST 3 LS ECS 3)', 1950, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO51', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify and name the different types of ecosystems in their country indicating their location on the map. (ST 3 LS ECS 4)', 1951, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO52', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify organisms found within a particular habitat. ', 1952, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO53', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify the basic needs of living organisms in various habitats. ', 1953, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO54', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe the characteristics of different types of environments (e.g., soft earth, trees and shrubs, seasonal flowering plants).', 1954, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('MATH-G4-PR-SCO69', 'MATH-G4-GT-ELO1', 'MATH-G4-GT', 'MATH', 'mathematics', 'G4', '4', 'Geometrical Thinking', 'construct 3D models based on given descriptions', 2452, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO55', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify at least five different habitats that exist in different ecosystems. ', 1955, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO56', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compare the habitats of many different kinds of Caribbean plants and animals.', 1956, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO57', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Construct a model of a habitat for a given organism.', 1957, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO58', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe the characteristics of particular organisms that help them to adapt to particular environments.', 1958, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO59', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify the needs of named organisms in a particular habitat (e.g., shelter from predators, food, water).', 1959, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO60', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify characteristics of organisms that might affect their survival.', 1960, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO61', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compare the needs of at least three types of organisms found in a particular habitat.', 1961, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO62', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Determine how and what features of the habitat are meeting the needs of each of the organisms (i.e., the degree to which a habitat meets the needs of an organism).', 1962, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO63', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Determine what features of the habitat are meeting the needs of each of the organisms (i.e., the degree to which a habitat meets the needs of an organism).', 1963, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO64', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Determine what features of the habitat that are not meeting the needs of each of the organisms (i.e., the degree to which a habitat does not meet the needs of an organism).', 1964, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO65', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Observe different habitats to determine key features/their characteristics and that of the animals living there.', 1965, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO66', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Recognize that organisms and their habitat form an interconnected system.', 1966, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO67', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Develop a clear argument about the survival of organisms in the habitat, supported by evidence.', 1967, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO68', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Make comparisons between different', 1968, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO69', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'organisms'' abilities to survive in the habitat.', 1969, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO70', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Classify different habitats based on their characteristics / Classify animals found in different habitats based on their characteristics/adaptations.', 1970, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO71', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Infer which habitat an organism might survive best in based on its physical/behavioral characteristics.', 1971, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO72', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Measure different variables within a given habitat, such as temperature, pH, etc.', 1972, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO73', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Communicate information gained from observation text, videos etc. with member of your group and the class.', 1973, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO74', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Construct an argument supported by evidence about the ability of organisms to survive in a habitat.', 1974, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO75', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compile/analyse data obtained from organisms observed in a habitat.', 1975, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO76', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Create and Interpret graph on data obtained from organisms observed in a habitat.', 1976, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO77', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Carry out simulations exercises to demonstrate the behaviour of animals in a habitat.', 1977, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO78', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Observe homes/habitats of different animals, indicating how each habitat satisfies the various needs of animals. (ST 2 LS ECS 3)', 1978, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO79', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Infer how food webs help to maintain nature''s balance, and identify the factors that may disrupt this balance. (ST 3 LS ECS 2)', 1979, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO80', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Construct and label simple food chains to depict feeding interrelationships among animals and plants. (ST 2-LS ECS 20)', 1980, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO81', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Construct and label simple food webs to show feeding linkages among animals in a given area(e.g., pond, a section of the school yard) (ST 3 LS ECS 1)', 1981, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO82', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Infer how food webs help to maintain nature’s balance, and identify the factors that may disrupt this balance. (ST 3 LS ECS 2)', 1982, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO83', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Interpret simple food webs, referring to the need of natures balance. (ST 4 LS ECS 1)', 1983, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO84', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Investigate the characteristics of mangroves, swamps, rainforests, pods and explain the importance of these habitats. (ST 4 LS ECS 2)', 1984, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO85', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Design and construct the model of a habitat. (ST 4 LS ECS 3)', 1985, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO86', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Appreciate the role that the different parts of a habitat play in the survival of an organism.', 1986, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO87', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Develop an appreciation for the role that adaptation to the habitat plays in an organism’s survival.', 1987, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO88', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Appreciate that not all organisms can survive well in a given habitat as not all habitats will meet all their needs.', 1988, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO89', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Show persistence when conducting studies of organisms within different habitats.', 1989, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO90', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Demonstrate interest in conservation of resources in each habitat to ensure that organisms’ needs are met.', 1990, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO91', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Use the inquiry approach in conducting various investigations.', 1991, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO92', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Show respect for evidence in making various claims about organisms living in habitats.', 1992, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO93', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Work collaboratively with their group members to complete various tasks.', 1993, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO94', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Stewardship/Respect for Living Things. When observing animals in their habitats, students should make sure that neither the animals nor their habitats are harmed.', 1994, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO95', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Safety:
•	While observing organisms in their habitats, students should exhibit appropriate behaviour to ensure that neither the organisms nor themselves get hurt. 
•	While observing organisms in their habitats, students should be respectful of the organisms and their habitats.
•	Students should be aware that some organisms can harm them. For example, ants can bite or plants can cause hives etc.', 1995, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO96', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'When conducting practical and group work, students should be sensitive about the physical or learning challenges of classmates or group members.', 1996, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G3-IRE-SCO97', 'SCIENCE-G3-IRE-ELO2', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Participate actively in classroom discussions and activities.', 1997, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO98', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Define the terms:
•	environment
•	environmental change
•	environmental destruction
•	pollution and pollutants
•	conservation and preservation
•	endangered species and extinct species                              
•	ecosystem restoration
•	habitat fragmentation', 1998, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO99', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Demonstrate they understand that changes in the environment affect the organisms that live in that environment.', 1999, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO100', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compare the effects of a habitat change on two different groups of organisms in the same habitat.', 2000, '[]'::jsonb, '2026-02-21T17:24:23.155683+00:00'),
  ('SCIENCE-G3-IRE-SCO101', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Account for changes that are observed in an ecosystem/habitat.', 2001, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO102', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain the importance of environmental conservation in their country.', 2002, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO103', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Distinguish between the terms endangered and extinct.', 2003, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO104', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain how loss of habitat results in the endangerment or extinction of species.', 2004, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO105', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Investigate the factors that cause and prevent environmental destruction.', 2005, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO106', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify organisms that are deemed to be endangered in the OECS region.', 2006, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO107', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify ways of conserving the environment.', 2007, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO108', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify local ecosystems in need of conservation or restoration.', 2008, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO109', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify some ways in which environmental destruction may be prevented.', 2009, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO110', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify solutions to specific problems caused when an ecosystem/habitat has undergone change.', 2010, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO111', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe ways in which plants respond to changes in their environment.', 2011, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO112', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe ways in which animals respond to changes in their environment.', 2012, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO113', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify some ways in which an ecosystem can change.', 2013, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO114', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'List factors that can bring about changes to ecosystems.', 2014, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-PR-SCO70', 'MATH-G4-GT-ELO1', 'MATH-G4-GT', 'MATH', 'mathematics', 'G4', '4', 'Geometrical Thinking', 'Apply spatial reasoning skills to make 2D and 3D composite objects', 2453, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO115', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe an ecosystem before changes occurred in it.', 2015, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO116', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe changes that have occurred in an environment.', 2016, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO117', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe the problems caused for the organisms living in this area.', 2017, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO118', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Assess the effects of the solution on the plants and animals within the environment.', 2018, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO119', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Document the resulting changes to plants and animals living within the changed environment, after the solution has been implemented.', 2019, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO120', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Give examples of organisms that have become extinct due to change in their habitat.', 2020, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO121', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Evaluate the solution to determine how the solution reduced the impact of the problem created by the environmental change in the system.', 2021, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO122', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Determine how changes to one part of the system due to the solution, affects the other parts of the system.', 2022, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO123', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain how environmental destruction can lead to changes in the diversity and number of organisms living in a habitat. Determine how the solution affects plants and animals.', 2023, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO124', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify different ways that organisms are adapting to changes in their habitats.', 2024, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO125', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify some natural events that cause change in an ecosystem.', 2025, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO126', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify some actions or activities of humans that negatively impact the environment.', 2026, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO127', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe how pollutants affect people’s activities and health. (ST 2 ESS ER 8)', 2027, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO128', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain with examples what are endangered species. (ST 2 LS ECS 12)', 2028, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO129', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Identify and discuss ways in which water may be polluted and ways in which it may be conserved. (ST 2 LS ECS 21)', 2029, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO130', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Explain to their classmates the need for environmental conservation in their country outlining possible scenarios if such protection is neglected. (ST 3 LS ECS 7)', 2030, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO131', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Define the term environmental destruction and investigate the factors that cause and prevent this destruction. (ST 2 LS ECS 24)', 2031, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO132', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Observe and record the effect of changes upon the living organisms and nonliving things in a small–scale environment.', 2032, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO133', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Distinguish between actions that harm a habitat/the environment from those that preserve it.', 2033, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO134', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Demonstrate how one would care for a habitat/environment.', 2034, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO135', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Predict how a specific environmental change might affect the survival of a plant or animal species.', 2035, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO136', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Describe the role of conservation methods in maintaining balance in the environment.', 2036, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO137', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Examine an ecosystem that has experienced change.', 2037, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO138', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compare and contrast an ecosystem/habitat before and after it has experienced a single disturbance.', 2038, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO139', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compare an ecosystem that has undergone change before and after a solution has been implemented.', 2039, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO140', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Infer the changes that can occur to a habitat due to an action on a habitat.', 2040, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO141', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Classify changes within an ecosystem based on the factors that caused them.', 2041, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO142', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Take different measurements within an ecosystem that has undergone changes before and after the solution was implemented.', 2042, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO143', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Hypothesize how an ecosystem will respond to a solution.', 2043, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO144', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Communicate findings from investigations to the class, group members and in the form of reports.', 2044, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO145', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Communicate effectively about environmental issues and their solutions.', 2045, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G3-IRE-SCO146', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Develop a proposed plan of action for the rehabilitation of a damaged habitat.', 2046, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO147', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Compile data obtained on a habitat/ecosystem that has experienced a disturbance.', 2047, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO148', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Interpret data obtained from the monitoring of a habitat to determine the effectiveness of a solution. ', 2048, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO149', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Graph results obtained from investigating damage caused to a named habitat.', 2049, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO150', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Distinguish between the causes of air pollution and water pollution.', 2050, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO151', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Infer how food webs help to maintain nature''s balance and identify the factors that may disrupt this balance. (ST 3 LS ECS 2)', 2051, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO152', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Appreciate the fragile nature of ecosystems.', 2052, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO153', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Appreciate the importance of caring for plants, animals and their environment.', 2053, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO154', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Recognize the role that humans play in protecting or destroying ecosystems.', 2054, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO155', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Appreciate that the environment needs to be protected.', 2055, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO156', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Show persistence in conducting investigations done on habitat destruction and restoration.', 2056, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO157', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Display interest about what is being done to protect and maintain different ecosystems in their country.', 2057, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO158', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Use the inquiry approach in their investigation of different habitats.', 2058, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO159', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Display respect for evidence generated from investigations done on habitat destruction and restoration.', 2059, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO160', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Use their inventiveness in the development of a plan for the restoration and monitoring of a habitat that has experienced change.', 2060, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO161', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Work collaboratively to propose a course of action to protect the habitat within a local ecosystem.', 2061, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO162', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Follow different safety rules which were developed to protect themselves and other organisms in their exploration/investigation of different habitats.', 2062, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO163', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'When carrying out their investigations, especially those done outdoors, extend a helping hand to persons who may have certain physical or learning challenges.', 2063, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IRE-SCO164', 'SCIENCE-G3-IRE-ELO3', 'SCIENCE-G3-IRE', 'SCIENCE', 'science', 'G3', '3', 'Interdependent Releationships in Ecosystems', 'Participate actively in classroom discussions on different aspects about habitat destruction and restoration.', 2064, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO1', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Define the terms:
•	Life cycle
•	Propagating
•	Reproducing
•	Vertebrates
•	Invertebrates
•	Metamorphosis
•	Pollination
•	Angiosperm
•	Cotyledon
•	Monocot
•	Dicot
•	Vegetative propagation (ST 3 LS DC 2) 
•	Bulbs
•	Rhizomes
•	Stolons (runners)
•	Tubers
•	Leaf propagation
•	Artificial vegetative propagation
•	Cuttings
•	Grafting
•	Layering', 2065, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO2', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Distinguish vertebrates and invertebrates.', 2066, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO3', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify similarities in life cycles.', 2067, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO4', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Journaling a life cycle (bean plant).', 2068, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO5', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Describe the main differences between monocots and dicots (ST 3 LS DC 3).', 2069, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO6', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Outline two natural methods of propagation in flowering plants, giving local examples (ST 3 LS DC 4).', 2070, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO7', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Describe and explain methods of vegetative propagation (ST 3 LS DC 5).', 2071, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO8', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Define the terms: vertebrates and invertebrates and list the five (5) classes of vertebrates (ST 3 LS DC 8).', 2072, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO9', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and name some characteristics of living things (ST LS DC 2).', 2073, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO10', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and name at least three (3) characteristics of living things (ST 2 LS DC 4).  ', 2074, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO11', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Observe the characteristics of life cycles.', 2075, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO12', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Classify vertebrates / invertebrates', 2076, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO13', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Communicate your research results identifying vegetative propagation in the community.', 2077, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO14', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Research and communicate a graphic of incomplete metamorphosis.', 2078, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO15', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Research and identify plants in the community that use natural vegetative propagation.', 2079, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO16', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Investigate information on a particular life cycle.', 2080, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO17', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Demonstrate Interest/Curiosity for the life cycles of a range of plants & animals.', 2081, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO18', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Demonstrate Stewardship/Respect for living things.', 2082, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO19', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 2083, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO20', 'SCIENCE-G3-IVT-ELO1', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Participate actively in classroom discussions.', 2084, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO21', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Define the terms:
•	Traits
•	Parents
•	Offspring
•	Hybridization
•	Reproduction
•	Flowering plants
•	Non-flowering plants
•	Living things
•	Herbivores
•	Carnivores
•	Selective breeding
•	Drought resistant
•	Disease resistant', 2085, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO22', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Outline the main features of a plant and name the parts (ST 1 LS ECS 5).', 2086, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO23', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and name at least three characteristics of living things. (ST2 LS DC 4).', 2087, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO24', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Discuss the importance of growth, development and reproduction in plants and animals (ST 4 LS SF 2).', 2088, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO25', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and describe the main features of different animals in their country (ST 1 LS ECS 9).', 2089, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO26', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Give examples of hybridization for improved plants.', 2090, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO27', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and describe the main features of different animals in their country (ST 1 LS ECS 9).', 2091, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO28', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Give examples for selective breeding for improved animals.', 2092, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO29', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Observe pictures of parents and offspring and identify similar and different traits.', 2093, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO30', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Interpret the text “Ugly Duckling.”', 2094, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO31', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Classify and give examples of flowering and nonflowering plants.', 2095, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G3-IVT-SCO32', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Compare pros and cons for modifying the genes in plants.', 2096, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO33', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and tabulate personal traits.', 2097, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO34', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Investigate in a field trip the traits of plants and animals.', 2098, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO35', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Compile pictures of parents', 2099, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO36', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Classify plants according to certain features such as size, shape of leaves, flowering and non- flowering (ST 1 LS ECS 6).', 2100, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO37', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Classify animals according to their size, body coverings, and the food they eat (ST 2 LS DC 2).', 2101, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO38', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Appreciation that humans have a variety of traits and no person should feel marginalised because they are different.', 2102, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO39', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Interest/Curiosity as to how plants and animal parents can produce a range of offspring.', 2103, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO40', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Inquiry about the ways selective breeding and hybridization can help third world countries.', 2104, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO41', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 2105, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-PR-SCO71', 'MATH-G4-GT-ELO1', 'MATH-G4-GT', 'MATH', 'mathematics', 'G4', '4', 'Geometrical Thinking', 'Make predictions about 2d and 3dcomposite objects', 2454, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO42', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Participate actively in classroom discussions.', 2106, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO43', 'SCIENCE-G3-IVT-ELO2', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Critically consider whether we should use the technology we have developed to create more GMO foods.', 2107, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO44', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Define the terms:
•	Climate Zone
•	Temperate zone
•	Polar zone
•	Tropical zone
•	Environment
•	Traits
•	Genes
•	Photosynthesis
•	Energy transformation
•	Evaporation', 2108, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO45', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Demonstrate they understand that plants and animals in different earth zones may look different because of temperature variations as they get further from the equator.', 2109, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO46', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Compare animals in different environmental conditions.', 2110, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO47', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Outline how soils are made from a variety of rocks (ST 3 ESS ER 3).', 2111, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO48', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Describe and demonstrate appropriate ways of feeding and caring for pets (ST 2 LS ECS 1).', 2112, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO49', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Describe the physical features of the parts of a plant, relating these features to their function (ST 3 LS SF 1).', 2113, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO50', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Discuss the importance of growth, development and reproduction in plants and animals (ST 4 LS SF 2).', 2114, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO51', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Explain the role of the sun as the main provider of heat and light on earth (ST 3 PS EN 2).', 2115, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO52', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Discuss simple examples of energy transformation (ST 3 PS EN 8).', 2116, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO53', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Observe pictures of living things and hypothesize how the environment in which they live may impact their traits.', 2117, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO54', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Measure water levels of evaporation.', 2118, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO55', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Tabulate water level data for evaporation.', 2119, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO56', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Graph the rate of evaporation.', 2120, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO57', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Calculate an evaporation rate for bright sunshine location.', 2121, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO58', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Classify animals according to size, body coverings, and food they eat (ST 2 LS DC 2).', 2122, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO59', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Classify soils as sand, clay and loam (ST 3 ESS ER 6).', 2123, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO60', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Investigate which soils retains water or drains quickest (ST 4 ESS ER 4).', 2124, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO61', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Compare the rate of evaporation of water under specific conditions (ST 4 ESS ER 7).', 2125, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO62', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Appreciation for the diversity of living things.', 2126, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO63', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Collaboration & Cooperation with peers.', 2127, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO64', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Stewardship/Respect for Living Things.', 2128, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO65', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges. ', 2129, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO66', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Participate actively in classroom discussions.', 2130, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO67', 'SCIENCE-G3-IVT-ELO3', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and appreciate the importance of caring for plants and animals and their environment (ST 2 LS ECS 4).', 2131, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO68', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Define the terms:
•	Habitat
•	Adaptation
•	Desert
•	Forest
•	Aquatic
•	Polar
•	Savannah
•	Camouflage
•	Spines
•	Manchineel tree
•	Predator
•	Prey
•	Reproduction
•	Offspring', 2132, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO69', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Demonstrate they understand that adaptations help living things to survive.', 2133, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO70', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Give examples of animals that have adapted.', 2134, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO71', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Give examples of plants that have adapted.', 2135, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO45', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Design and construct a project to learn how we can reduce climate change. ', 2200, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO72', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Give reasons why living things might adapt given their environment.', 2136, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO73', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify some features of organisms that allow them to survive in their homes /habitat (ST 1 LS ECS 4)', 2137, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO74', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and describe the main features of different animals found in their country (ST 1 LS ECS 9).', 2138, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO75', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and describe natural defenses that local animals use to help them survive (spines, camouflage etc.) (ST 1 LS ECS 12.)', 2139, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO76', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Identify and name at least three characteristics of living things (ST 2 LS DC 4).', 2140, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO77', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Explain how some features of organisms enable their survival in habitats (ST 2 LS ECS 5).', 2141, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO78', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Discuss the importance of growth, development and reproduction in plants and animals (ST 4 LS SF 2).', 2142, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO79', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Observe carefully pictures of animals and hypothesize how their adaptations have helped with their survival.', 2143, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G3-IVT-SCO80', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Compare habitats and suggest how the conditions shape the adaptations of living things.', 2144, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO81', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Rationalize the appropriateness of animals’ body shapes that fit their daily needs. (e.g. birds’ beaks)', 2145, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO82', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Research adaptations living things in your own country.', 2146, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO83', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Communicate research findings through posters and digital expressions.', 2147, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO84', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Distinguish definitions of predator and prey.', 2148, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO85', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Appreciation of the diversity of habitats and the importance of humans protecting them.', 2149, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO86', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Interest/Curiosity to investigate adaptations in living things.', 2150, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO87', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Collaboration & Cooperation in research and communication of findings.', 2151, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO88', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Stewardship/Respect for Living Things.', 2152, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO89', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 2153, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO90', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Participate actively in classroom discussions.', 2154, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-IVT-SCO91', 'SCIENCE-G3-IVT-ELO4', 'SCIENCE-G3-IVT', 'SCIENCE', 'science', 'G3', '3', 'Inheritance and Variation of Traits: Life Cycles and Traits', 'Demonstrate respect for plants and animals (ST 4 LS DC 2).', 2155, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO1', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Define the terms:
•	Weather
•	Weather forecasting
•	meteorologist/ meteorology
•	temperature
•	precipitation
•	wind direction
•	clouds
•	moisture/humidity
•	climate
•	atmosphere', 2156, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO2', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Demonstrate an understanding of the formation of clouds.', 2157, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO3', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Review and explain the components and processes involved in the water cycle.', 2158, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO4', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Distinguish between weather and climate.', 2159, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO5', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Identify and describe weather patterns at a particular time at a given time.', 2160, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO6', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Identify instruments used to measure the elements of weather.', 2161, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO7', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Demonstrate an understanding of how to use:
a)	thermometer to measure the degree of hotness and coldness
b)	anemometer to measure wind speed.
c)	rain gauge to measure the amount of rainfall.
d)	windvane to measure wind direction.', 2162, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO8', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Identify types of weather conditions by examining weather charts. (ST 3 ESS EW 10)', 2163, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO9', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Investigate and report from data collected about the weather over a period, using simple graphs. (ST 4 ESS EW 7)', 2164, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO10', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Conduct a simple experiment to find out if the weather affects evaporation in natural settings. (ST 3 ESS ER 8)', 2165, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO11', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Communicate effectively results of weather experiments.', 2166, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO46', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Develop appreciation for Science by recognising how climate affects our daily lives.', 2201, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO12', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Analyze a table and bar graph and make predictions based on the average temperature, wind speed and precipitation in a particular area.', 2167, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO13', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'To work respectfully with others in exploring and investigating the weather.', 2168, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO14', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Demonstrate a concern for weather conservation as well as protection of our clean water sources.', 2169, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO15', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Describe the weather patterns that affect the activities of people and the effects they can have on our daily lives. Eg flooding, hurricanes, dehydration, sporting activities, drought.', 2170, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO16', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Develop a curiosity of how air, temperature, moisture, precipitation, wind speed and direction make up the weather in a particular place and time.', 2171, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO17', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Based on an understanding of the water cycle, show concern for the protection of water resources, the effects of pollution and climate change.', 2172, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO18', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Work cooperatively with peers.', 2173, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO19', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Participate in classroom discussions.', 2174, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO20', 'SCIENCE-G3-WC-ELO1', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'When conducting practical and group work., display sensitivity and offer assistance to peers who may have physical or learning challenges ', 2175, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO21', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Define the terms:
•	Equator o Season o Tilt o Rotate
•	Orbit
•	Northern Hemisphere o Sothern Hemisphere o Direct sunlight o Indirect sunlight
•	Climatic zones:
a)	polar/frigid
b)	temperate
c)	tropical/torrid
•	North /South pole
•	Climate
•	Weather
•	Temperature
•	Rainfall
•	Pressure
•	Wind Speed
•	Humidity
•	Greenhouse effect
•	Global warming
•	Carbon dioxide', 2176, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO22', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Identify and name the sun, earth and the moon as parts of the solar system. (ST 1 ESS SS 2)', 2177, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO23', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Explain, what is weather. (ST ESS EW 1)', 2178, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO24', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Describe how temperature affects weather (ST ESS EW 8)', 2179, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO25', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Explain the role of the sun as the main provider of heat and light on the earth. (ST 3 PS EN 2)', 2180, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO26', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Identify and discuss some of the unintended consequences of using fuels for transport and production of materials for commerce. (e.g. pollution). (ST 3 PS EN 5)', 2181, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO27', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Sustainable use of resources would help to minimize pollution and destruction of the environment. (ST 3 STSE 1)', 2182, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO28', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Describe and discuss how burning can cause air pollution. (ST 6 ESS ER 4)', 2183, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO29', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Define the terms: rotate, revolve, planet, star, satellite.(ST 3 ESS SS 2)', 2184, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO30', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Explain how the tilt of the earth on its rotational axis can cause the sun’s rays to be direct and indirect for different parts of the earth and therefore lead to temperature changes on the surface (seasonal changes)', 2185, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO31', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Demonstrate an understanding that the earth is divided into three major climatic zones.', 2186, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO32', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Discuss the characteristics of each type of climate.', 2187, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO33', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Compare the different types of climates.', 2188, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO34', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Identify the plants and animals that can be found in each climatic zone.', 2189, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO35', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Explain how people adapt to live in the different climatic zones.', 2190, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO36', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Explain in simplified terms the process of global warming.', 2191, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO37', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Observe different types of weather --rainy, sunny, cloudy windy. (ST 2 ESS EW 1)', 2192, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G3-WC-SCO38', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Use a thermometer to measure temperature, explaining how the device works. (ST 3 ESS EW 9)', 2193, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO39', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Identify types of weather conditions by examining weather charts. (ST 3 ESS EW 10)', 2194, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO40', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Compare direct and indirect light using a flashlight (torch) to show how the sun’s energy can be spread out if it shines on the earth at an angle.', 2195, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO41', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Interpret models of the earth and sun and how they interact in the universe. (daily rotation, yearly orbit, earth’s axis & tilt)', 2196, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO42', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Predict weather patterns. (ST 2 ESS EW 4)', 2197, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO43', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Analyse weather events.', 2198, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO44', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Use the weather cycle to explain how/why humidity occurs.', 2199, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-PR-SCO68', 'MATH-G4-GT-ELO1', 'MATH-G4-GT', 'MATH', 'mathematics', 'G4', '4', 'Geometrical Thinking', 'draw a picture of 3D models based on given descriptions', 2451, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO47', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Willingly participate in activity to identify the climate of different regions of the world.', 2202, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO48', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Recognise the effects of climate change in a region of the world and take the necessary actions to reduce the effects of climate change.', 2203, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO49', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'When undertaking classroom activities, display sensitivity to and offer assistance to peers who may have physical or learning challenges.', 2204, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO50', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Participate actively in classroom discussions.', 2205, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO51', 'SCIENCE-G3-WC-ELO2', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Consider the dilemma of abundant fossil fuel resources and the damage burning these will inflict to our environment.', 2206, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO52', 'SCIENCE-G3-WC-ELO3', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Define the terms:
•	weather events
•	hurricane
•	typhoon
•	tornado
•	drought
•	erosion
•	landslides
•	land-borne floods
•	sea-borne floods
•	tsunami
•	pitch roof vs. flat roof
•	gable roof vs. hip roof
•	levee', 2207, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO53', 'SCIENCE-G3-WC-ELO3', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Discuss how the various weather patterns affect their activities, the type of clothes they wear, and ways of dealing with various weather types. (ST 1 ESS EW 4)', 2208, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SCIENCE-G3-WC-SCO54', 'SCIENCE-G3-WC-ELO3', 'SCIENCE-G3-WC', 'SCIENCE', 'science', 'G3', '3', 'Weather and Climate', 'Explain a problem in their own words and solutions related to the problem. (ST 1 TE UT 3)', 2209, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
