  ('SS-G3-EDM-SCO5', 'SS-G3-EDM-ELO2', 'SS-G3-EDM', 'SS', 'social-studies', 'G3', '3', 'Economic Decision Making', '3-EDM- S-2- Explore the ways  in which our people  can earn a living through culture', 2281, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SS-G3-EDM-SCO6', 'SS-G3-EDM-ELO2', 'SS-G3-EDM', 'SS', 'social-studies', 'G3', '3', 'Economic Decision Making', '3-EDM-V-2Appreciate how culture shapes our identity and economy', 2282, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SS-G3-EDM-SCO7', 'SS-G3-EDM-ELO3', 'SS-G3-EDM', 'SS', 'social-studies', 'G3', '3', 'Economic Decision Making', '3-EDM-K-3 Define the term population and understand its significance in the context of our region', 2283, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('SS-G3-EDM-SCO8', 'SS-G3-EDM-ELO3', 'SS-G3-EDM', 'SS', 'social-studies', 'G3', '3', 'Economic Decision Making', '3-EDM-S-3 - Explain how changes in population can affect our region''s resources and services.', 2284, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
