  ('SS-G3-EDM-SCO10', 'SS-G3-EDM-ELO4', 'SS-G3-EDM', 'SS', 'social-studies', 'G3', '3', 'Economic Decision Making', '3-EDM-K-4 Distinguish between immigration and emigration ', 2286, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
