  ('MATH-G4-NS-SCO1', 'MATH-G4-NS-ELO1', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'skip count by 2s, 5s, 10s, 50s, 100s, and 1000s from any number to 10 000', 2289, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
