INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G4-NS-SCO6', 'MATH-G4-NS-ELO2', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Match number words/names and numerals up to 10,000 with the quantities they represent.  ', 2294, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO7', 'MATH-G4-NS-ELO2', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Represent whole numbers up to 10,000 using various models (concretely, pictorially, and symbolically) ', 2295, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO8', 'MATH-G4-NS-ELO2', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Read and write 4-digit whole numbers up to 10 000 in standard and expanded form ', 2296, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO9', 'MATH-G4-NS-ELO2', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Solve problems using real-life situations involving reading, writing, and representing whole numbers up to 10 000. ', 2297, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO10', 'MATH-G4-NS-ELO3', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Compare the values of two 4-digit whole numbers using the <, > or =', 2298, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO11', 'MATH-G4-NS-ELO3', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Use different strategies to find numbers that are 100, 1000, or 10 000 more or less than a given number up to 4 digits', 2299, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO12', 'MATH-G4-NS-ELO3', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Compose and solve real-life situations/ problems involving the comparison of whole numbers up to 4 digits.', 2300, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO13', 'MATH-G4-NS-ELO3', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Identify the total value of each digit in a four digit number using concrete materials', 2301, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO14', 'MATH-G4-NS-ELO3', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Arrange in ascending and descending order a set of whole numbers up to 5 numbers.', 2302, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO15', 'MATH-G4-NS-ELO3', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Create pictorial representations to illustrate the difference between the values of a pair of whole numbers.', 2303, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO16', 'MATH-G4-NS-ELO3', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Recognize the practical relevance of comparing numbers in everyday situations like budgeting expenses or comparing prices, fostering a sense of mastery and motivation in mathematical reasoning.', 2304, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO17', 'MATH-G4-NS-ELO4', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'State the place value of any digit within a whole number up to 10,000.', 2305, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO18', 'MATH-G4-NS-ELO4', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Represent the place value of a numeral in context, up to 10 000 concretely, pictorially and symbolically. ', 2306, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO19', 'MATH-G4-NS-ELO4', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Identify and apply the principle that in a whole number up to four digits, each digit’s value is ten times greater than its value in the place immediately to its right.', 2307, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO20', 'MATH-G4-NS-ELO4', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Explain the pattern of regularity in the place value system', 2308, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO21', 'MATH-G4-NS-ELO4', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Recognize and articulate', 2309, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO22', 'MATH-G4-NS-ELO4', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Round off any whole number up to 10,000 to the nearest 100 and 1000', 2310, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO23', 'MATH-G4-NS-ELO4', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Compose and solve mathematical problems or puzzles, recognizing simple patterns and relationships among digits in a whole number.', 2311, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO24', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Explain equivalence of fractions in special cases, and compare fractions by reasoning about their size;', 2312, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO25', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Describe two fractions as equivalent (equal) if they are the same size parts of the same one-whole, or the same point on a number line.', 2313, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO26', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Explain why the fractions are equivalent, e.g., by using a visual fraction model.', 2314, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO27', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Represent proper fractions and decimal tenths concretely (fraction strips, Cuisenaire rods, etc.)', 2315, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO28', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Represent proper fractions and decimal tenths pictorially (number lines, drawings, etc.), contextually and symbolically.', 2316, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO29', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Represent proper fractions as equal parts of one-whole region, set or measure', 2317, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO30', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Model, identify, and generate simple equivalent fractions, e.g. 1/2, 2/4, 4/6, =2/3 1/2=', 2318, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO31', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Express whole numbers as fractions and recognize fractions that are equivalent to whole numbers. Examples:
Express 3 in the form of 3 =  3/1; recognize that 6/1= 6; locate 4/4 and 1 at the same point of a number line diagram. ', 2319, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO32', 'MATH-G4-NS-ELO5', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Use equivalence fraction in solving problems involving fractions', 2320, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO33', 'MATH-G4-NS-ELO6', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Compare unit fractions and their fraction families;', 2321, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO34', 'MATH-G4-NS-ELO6', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Compare other fractions with benchmark fractions (E.g. 1/4, ½, 3/4 );', 2322, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO35', 'MATH-G4-NS-ELO6', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Compare two fractions with the same numerator or the same denominator by reasoning about their size.', 2323, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO36', 'MATH-G4-NS-ELO6', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Recognize that comparisons are valid only when the two fractions refer to the same whole.', 2324, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO37', 'MATH-G4-NS-ELO6', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Record the results of comparisons with the symbols>, =, or <, and justify the conclusions, e.g., by using a visual fraction model;', 2325, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO38', 'MATH-G4-NS-ELO6', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Recognize the importance of equivalent fractions when comparing fractions.', 2326, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO39', 'MATH-G4-NS-ELO7', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Represent decimals using concrete materials (tenths) (base ten blocks).', 2327, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO40', 'MATH-G4-NS-ELO7', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Use appropriate language to describe decimals (tenths)', 2328, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO41', 'MATH-G4-NS-ELO7', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Create pictorial models (number lines, charts) to illustrate decimals (tenths)', 2329, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO42', 'MATH-G4-NS-ELO7', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Write decimals using symbolic notation. (tenths)', 2330, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO43', 'MATH-G4-NS-ELO7', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Communicate orally the value of a decimal through tenths. For example, in 999.2, the 2 is in the tenths place and has a value of two tenths (2/10).', 2331, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO44', 'MATH-G4-NS-ELO7', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Apply decimal numbers in real life situations.', 2332, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO45', 'MATH-G4-NS-ELO8', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Compare two decimal values using appropriate symbols, <, >, =.', 2333, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO46', 'MATH-G4-NS-ELO8', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Round off decimals to the nearest whole number.', 2334, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO47', 'MATH-G4-NS-ELO8', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Arrange a set of decimal numbers between 0 and 10 in ascending/descending order.', 2335, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO48', 'MATH-G4-NS-ELO8', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Write a decimal number (one decimal place) in the correct position on a number line.', 2336, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO49', 'MATH-G4-NS-ELO8', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Use concrete materials or pictorial representations to demonstrate the equivalence between fractions and decimals.', 2337, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO50', 'MATH-G4-NS-ELO8', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Students will display appreciation for comparing decimal numbers in real life situations by applying decimal numbers in measurements.', 2338, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO51', 'MATH-G4-NS-ELO9', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Read and write the number names for decimals up to tenths using base ten numerals up to 10 000', 2339, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO52', 'MATH-G4-NS-ELO9', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Represent the place value of various groupings concretely, pictorial, contextually and symbolically.', 2340, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO53', 'MATH-G4-NS-ELO9', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Express decimal numbers up to tenths in expanded form.', 2341, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO54', 'MATH-G4-NS-ELO9', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Describe the regular pattern of the place value system for numbers up to the tenth place.', 2342, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-NS-SCO55', 'MATH-G4-NS-ELO9', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Identify the total values of digits based the its place value of numbers up to the tenths place.', 2343, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('MATH-G4-NS-SCO56', 'MATH-G4-NS-ELO9', 'MATH-G4-NS', 'MATH', 'mathematics', 'G4', '4', 'Number Sense', 'Solve word problems involving decimals in the context of real-life situations.', 2344, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO1', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Decompose a fraction less than or equal to 1 into a sum of fractions with the same denominator in more than one way, recording each decomposition with an equation.', 2345, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO2', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Justify decompositions with a visual model, such as a tape diagram or number line.', 2346, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO3', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'use concrete models or drawings and strategies based on place value to add and subtract decimals to tenths.', 2347, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO4', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Accurately Add and subtract decimals in base 10 up to tenths, including lining up the decimal points and carrying over when necessary.', 2348, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO5', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Accurately perform addition and subtraction of fractions by understanding and applying the relationship between the numerator and denominator.', 2349, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO6', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Demonstrate using models how fractions can be decomposed into a sum of fractions with the same denominator.  ', 2350, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO7', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Manipulate place value models, such as base-ten blocks or grids, to visually represent and carry out addition and subtraction of decimals to tenths.', 2351, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO8', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Represent the addition and subtraction of decimals on a number line, recognizing the movement to the right for addition and to the left for subtraction.', 2352, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
  ('MATH-G4-ON-SCO9', 'MATH-G4-ON-ELO1', 'MATH-G4-ON', 'MATH', 'mathematics', 'G4', '4', 'Operations with Numbers', 'Work collaboratively to decompose fractions with like denominators', 2353, '[]'::jsonb, '2026-02-21T17:24:23.983713+00:00'),
