  ('MATH-G4-DH-SCO26', 'MATH-G4-DH-ELO4', 'MATH-G4-DH', 'MATH', 'mathematics', 'G4', '4', 'Data Handling and Probability', 'Use manipulatives (such as blocks or counters) to create two different', 2584, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('MATH-G4-DH-SCO27', 'MATH-G4-DH-ELO4', 'MATH-G4-DH', 'MATH', 'mathematics', 'G4', '4', 'Data Handling and Probability', 'one-to-one correspondence and the other using many-to-one correspondence. Take pictures of both graphs and explain the similarities and differences.', 2585, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
