  ('LANG-G4-LS-SCO9', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'Listen attentively and critically to fiction and nonfiction texts and music to demonstrate understanding of the mood, main idea, supporting details, theme, moral etc.', 2612, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO10', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'Develop competence in analyzing subtle messages in a conversation, music, advertisements, speeches, and media. ', 2613, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
