  ('LANG-G4-LS-SCO12', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'discuss issues and/or solutions to local, regional and world problems by extending use of questioning to consider: why? how? when?  what if? what else?', 2615, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO13', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'engage in back-and-forth conversations with peers during collaborative activities by adding relevant comments and questions to advance the dialogue. ', 2616, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO14', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'express their ideas and opinions with increasing respect and confidence.', 2617, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO15', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'practice active listening strategies including eye contact with affirming words/gestures to show whole-hearted engagement during peer discussions.', 2618, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO16', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'experiment with nonverbal communication (signing, mime, facial expressions, etc.)', 2619, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
