  ('LANG-G4-LS-SCO20', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'Participate in the early stages of debate, considering the multiple viewpoints and finding common grounds', 2623, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO21', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'Integrate listening and speaking skills across various subject areas, such as mathematics, social studies, and science.', 2624, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO22', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'Explore and discuss ideas, opinions, and feelings on topics of personal and social interest using both Standard English and Home Language(s).', 2625, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO23', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'demonstrate awareness of the kind of language appropriate for different situations and audiences  ', 2626, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO24', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'Deepen understanding of the importance of word choice, tone of voice, volume, projection, facial expression, and gesture appropriate to the speaking occasion', 2627, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-LS-SCO25', 'LANG-G4-LS-ELO1', 'LANG-G4-LS', 'LANG', 'language-arts', 'G4', '4', 'Listening and Speaking', 'Listen to identify the tone, mood and the emotion conveyed by a speaker in an oral communication.  ', 2628, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
